+  background: linear-gradient(135deg, rgba(66, 133, 244, 0.92), rgba(52, 168, 83, 0.86));
+  color: #091018;
+  border-color: rgba(255, 255, 255, 0.12);
+  box-shadow: 0 18px 44px rgba(66, 133, 244, 0.18), 0 18px 44px rgba(52, 168, 83, 0.14);
+}
+
+.btn--ghost {
+  background: rgba(255, 255, 255, 0.06);
+  color: var(--text);
+}
+
+.btn:hover {
+  transform: translateY(-1px);
+}
+
+.note {
+  margin: 0;
+  color: rgba(243, 244, 246, 0.56);
+  font-size: 13px;
+  opacity: 0;
+  transform: translateY(10px);
+  animation: rise 700ms cubic-bezier(0.2, 1, 0.2, 1) 520ms forwards;
+}
+
+.note code {
+  background: rgba(255, 255, 255, 0.06);
+  border: 1px solid rgba(255, 255, 255, 0.07);
+  padding: 2px 6px;
+  border-radius: 8px;
+  color: rgba(243, 244, 246, 0.84);
+}
+
+.hero__panel {
+  display: grid;
+  gap: 14px;
+  opacity: 0;
+  transform: translateY(10px);
+  animation: rise 700ms cubic-bezier(0.2, 1, 0.2, 1) 260ms forwards;
+}
+
+.card {
+  border: 1px solid var(--stroke);
+  background: var(--card);
+  border-radius: var(--radius2);
+  box-shadow: var(--shadow);
+  overflow: hidden;
+}
+
+.term__bar {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 12px 14px;
+  background: rgba(12, 12, 18, 0.58);
+  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
+}
+
+.dots {
+  display: inline-flex;
+  gap: 6px;
+}
+
+.dot {
+  width: 11px;
+  height: 11px;
+  border-radius: 999px;
+}
+
+.dot--r {
+  background: #ff5f57;
+}
+.dot--y {
+  background: #febc2e;
+}
+.dot--g {
+  background: #28c840;
+}
+
+.term__title {
+  margin-left: auto;
+  margin-right: auto;
+  font-family: var(--mono);
+  font-size: 12px;
+  color: rgba(243, 244, 246, 0.55);
+}
+
+.term__body {
+  padding: 14px 14px 16px;
+  background: rgba(11, 11, 17, 0.6);
+}
+
+.term__pre {
+  margin: 0;
+  font-family: var(--mono);
+  font-size: 12.5px;
+  color: rgba(243, 244, 246, 0.86);
+  line-height: 1.6;
+  white-space: pre-wrap;
+}
+
+.term__pre code {
+  display: block;
+}
+
+.meta {
+  padding: 14px 14px;
+  background: var(--card2);
+  border: 1px solid rgba(255, 255, 255, 0.06);
+  box-shadow: var(--shadow2);
+}
+
+.meta__item {
+  display: grid;
+  grid-template-columns: 90px 1fr;
+  gap: 12px;
+  padding: 10px 0;
+}
+
+.meta__item + .meta__item {
+  border-top: 1px solid rgba(255, 255, 255, 0.06);
+}
+
+.meta__k {
+  color: rgba(243, 244, 246, 0.55);
+  font-size: 12px;
+  letter-spacing: 0.06em;
+  text-transform: uppercase;
+}
+
+.meta__v {
+  color: rgba(243, 244, 246, 0.86);
+  font-size: 13px;
+}
+
+.meta__v code {
+  background: rgba(255, 255, 255, 0.06);
+  border: 1px solid rgba(255, 255, 255, 0.07);
+  padding: 2px 6px;
+  border-radius: 8px;
+  color: rgba(243, 244, 246, 0.9);
+}

